// Parsear resposta do Mistral OCR e separar texto de imagens
const ocrResult = $input.first().json;
const docUrl = ocrResult.document?.document_url || '';
const sourceFile = docUrl.split('/').pop() || ocrResult.model || 'unknown.pdf';
const items = [];

if (ocrResult.pages) {
  for (const page of ocrResult.pages) {
    // Chunk de texto (markdown da página)
    if (page.markdown && page.markdown.trim()) {
      items.push({
        json: {
          text: page.markdown,
          itemType: 'text',
          metadata: {
            source_file: sourceFile,
            page_number: page.index || 0,
            source_type: 'ocr_text'
          }
        }
      });
    }

    // Chunks de imagens (elementos visuais com base64)
    if (page.images && page.images.length > 0) {
      for (let i = 0; i < page.images.length; i++) {
        const img = page.images[i];
        if (img.image_base64) {
          const annotation = img.annotation || {};

          // Limpar base64: remover prefixo data URI se existir
          let rawBase64 = img.image_base64;
          let detectedMime = 'image/jpeg';
          if (rawBase64.startsWith('data:')) {
            const match = rawBase64.match(/^data:(image\/[a-zA-Z+]+);base64,/);
            if (match) {
              detectedMime = match[1];
              rawBase64 = rawBase64.substring(match[0].length);
            }
          }

          // Detectar mime pelo header do base64 se não veio do prefixo
          if (!img.image_base64.startsWith('data:')) {
            if (rawBase64.startsWith('/9j/')) detectedMime = 'image/jpeg';
            else if (rawBase64.startsWith('iVBOR')) detectedMime = 'image/png';
            else if (rawBase64.startsWith('R0lGO')) detectedMime = 'image/gif';
            else if (rawBase64.startsWith('UklGR')) detectedMime = 'image/webp';
          }

          const ext = detectedMime.split('/')[1] || 'png';

          items.push({
            json: {
              itemType: 'image',
              annotation: annotation,
              prompt_context: [
                `Tipo do elemento: ${annotation.element_type || 'desconhecido'}`,
                `Título: ${annotation.title || 'sem título'}`,
                `Texto visível (OCR): ${annotation.visible_text || 'nenhum'}`,
                `Seção do documento: ${annotation.page_section || 'não identificada'}`
              ].join('\n'),
              metadata: {
                source_file: sourceFile,
                page_number: page.index || 0,
                element_type: annotation.element_type || 'unknown',
                element_title: annotation.title || '',
                page_section: annotation.page_section || '',
                visible_text: annotation.visible_text || '',
                source_type: 'vision'
              }
            },
            binary: {
              image: {
                data: Buffer.from(rawBase64, 'base64').toString('base64'),
                mimeType: detectedMime,
                fileName: `${sourceFile}_page${page.index || 0}_img${i}.${ext}`
              }
            }
          });
        }
      }
    }
  }
}

if (items.length === 0) {
  items.push({ json: { itemType: 'empty', text: 'Nenhum conteúdo extraído' } });
}

return items;

// Combinar descrição do Anthropic com metadata do OCR
// Pegar a descrição gerada pelo Anthropic (testar vários campos possíveis)
const description = $json.output || $json.text || $json.content || $json.message || JSON.stringify($json);

// Pegar metadata do item original via node Separar Texto e Imagens
// que está no caminho de execução deste branch
let metadata = {};
let annotation = {};
try {
  const original = $('Separar Texto e Imagens').first();
  metadata = original.json.metadata || {};
  annotation = original.json.annotation || {};
} catch (e) {
  // Fallback: tentar extrair do próprio input
  metadata = $json.metadata || {};
  annotation = $json.annotation || {};
}

return {
  json: {
    text: [
      `## ${metadata.element_title || annotation.title || 'Elemento Visual'}`,
      `**Tipo:** ${metadata.element_type || 'desconhecido'}`,
      `**Seção:** ${metadata.page_section || 'não identificada'}`,
      '',
      description,
      '',
      `**Texto OCR original:** ${metadata.visible_text || 'nenhum'}`
    ].join('\n'),
    metadata: {
      source_file: metadata.source_file || '',
      page_number: metadata.page_number || 0,
      element_type: metadata.element_type || 'unknown',
      element_title: metadata.element_title || '',
      page_section: metadata.page_section || '',
      source_type: 'vision'
    }
  }
};

// ================================================================
// PREPARADOR - Monta prompt de avaliação para o Agente Juiz
// ================================================================

const GABARITO = $("Gabarito").first().json;

const AGENT_MAP = [
  { modelo: 'Gemini',    grupo: 'Sem RAG' },
  { modelo: 'Anthropic', grupo: 'Sem RAG' },
  { modelo: 'Ollama',    grupo: 'Sem RAG' },
  { modelo: 'Gemini',    grupo: 'Com RAG' },
  { modelo: 'Anthropic', grupo: 'Com RAG' },
  { modelo: 'Ollama',    grupo: 'Com RAG' },
];

// ----------------------------------------------------------------
// HELPERS
// ----------------------------------------------------------------

const normalize = (s) =>
  s.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim();

function identificarPergunta(inputText) {
  if (!inputText) return null;

  const norm = normalize(inputText);
  let melhorMatch = null;
  let melhorScore = 0;

  for (const [id, gab] of Object.entries(GABARITO)) {
    const score = gab.keywords.filter(kw => norm.includes(normalize(kw))).length;

    if (score > melhorScore) {
      melhorScore = score;
      melhorMatch = { id: Number(id), ...gab };
    }
  }

  return melhorScore >= 2 ? melhorMatch : null;
}

function coletarRespostas(items) {
  const respostas = [];
  const indisponiveis = [];

  for (let i = 0; i < items.length; i++) {
    const meta = AGENT_MAP[i] ?? { modelo: `Agente_${i}`, grupo: 'Desconhecido' };
    const resposta = (items[i].json.output ?? '').trim();

    if (resposta) {
      respostas.push({ ...meta, resposta });
    } else {
      indisponiveis.push(`${meta.modelo} (${meta.grupo})`);
    }
  }

  return { respostas, indisponiveis };
}

// ----------------------------------------------------------------
// MONTAGEM DO PROMPT
// ----------------------------------------------------------------

function montarSecaoGabarito(pergunta) {
  return [
    `## PERGUNTA AVALIADA`,
    pergunta.pergunta,
    ``,
    `## GABARITO (RESPOSTA CORRETA)`,
    pergunta.resposta_esperada,
    ``,
    `## DADOS-CHAVE ESPERADOS`,
    ...pergunta.dados_chave.map(d => `- ${d}`),
  ].join('\n');
}

function montarSecaoSemGabarito(inputText) {
  const gabaritosRef = Object.entries(GABARITO)
    .map(([id, gab]) => `Pergunta ${id}: ${gab.pergunta}\nResposta esperada: ${gab.resposta_esperada}`)
    .join('\n\n');

  return [
    `## PERGUNTA DO USUARIO`,
    inputText || '(nao identificada)',
    ``,
    `## NOTA: Pergunta nao corresponde ao banco de perguntas pre-definidas.`,
    `Avalie as respostas com base na coerencia interna e qualidade geral.`,
    ``,
    `## GABARITOS DISPONIVEIS (para referencia)`,
    gabaritosRef,
  ].join('\n');
}

function montarSecaoRespostas(respostas) {
  const blocos = respostas
    .map(r => `### ${r.modelo} (${r.grupo})\n${r.resposta}`)
    .join('\n\n---\n\n');

  return `## RESPOSTAS DOS AGENTES PARA AVALIAR\n\n${blocos}`;
}

function montarSecaoIndisponiveis(indisponiveis) {
  if (!indisponiveis.length) return '';

  return [
    `## AGENTES INDISPONIVEIS`,
    ...indisponiveis.map(a => `- ${a}`),
  ].join('\n');
}

// ----------------------------------------------------------------
// EXECUÇÃO
// ----------------------------------------------------------------

const inputText = $('When chat message received').first().json.chatInput ?? '';
const pergunta  = identificarPergunta(inputText);

const { respostas, indisponiveis } = coletarRespostas($input.all());

const secoes = [
  pergunta ? montarSecaoGabarito(pergunta) : montarSecaoSemGabarito(inputText),
  montarSecaoRespostas(respostas),
  montarSecaoIndisponiveis(indisponiveis),
].filter(Boolean);

const promptJuiz = secoes.join('\n\n');

return [{
  json: {
    prompt_avaliacao: promptJuiz,
    pergunta_id: pergunta?.id ?? 0,
  }
}];
